// src/config/equipment.js
// Configuration file for equipment models

export const equipmentConfig = {
  // Map of model types to file paths
  modelPaths: {
    'treadmill': '/assets/models/treadmill.glb',
    'bench': '/assets/models/bench.glb',
    'dumbbellRack': '/assets/models/dumbbell-rack.glb',
    'squat-rack': '/assets/models/squat-rack.glb',
    'elliptical': '/assets/models/elliptical.glb',
    'rowing-machine': '/assets/models/rowing-machine.glb',
    'yoga-mat': '/assets/models/yoga-mat.glb',
    'exercise-bike': '/assets/models/exercise-bike.glb'
  },
  
  // Map of model types to their physical dimensions (in meters)
  // Used for proper placement and collision detection
  dimensions: {
    'treadmill': { width: 0.9, height: 1.5, depth: 1.8 },
    'bench': { width: 0.6, height: 0.5, depth: 1.2 },
    'dumbbellRack': { width: 1.2, height: 0.9, depth: 0.6 },
    'squat-rack': { width: 1.2, height: 2.1, depth: 1.2 },
    'elliptical': { width: 0.7, height: 1.7, depth: 1.4 },
    'rowing-machine': { width: 0.5, height: 0.9, depth: 2.4 },
    'yoga-mat': { width: 0.6, height: 0.02, depth: 1.8 },
    'exercise-bike': { width: 0.6, height: 1.2, depth: 1.1 }
  },
  
  // Equipment catalog for UI
  catalog: {
    'Cardio': [
      { id: 'treadmill', name: 'Treadmill', icon: '/assets/icons/treadmill.png' },
      { id: 'elliptical', name: 'Elliptical', icon: '/assets/icons/elliptical.png' },
      { id: 'exercise-bike', name: 'Exercise Bike', icon: '/assets/icons/exercise-bike.png' },
      { id: 'rowing-machine', name: 'Rowing Machine', icon: '/assets/icons/rowing-machine.png' }
    ],
    'Strength': [
      { id: 'bench', name: 'Bench', icon: '/assets/icons/bench.png' },
      { id: 'squat-rack', name: 'Squat Rack', icon: '/assets/icons/squat-rack.png' },
      { id: 'dumbbellRack', name: 'Dumbbell Rack', icon: '/assets/icons/dumbbell-rack.png' }
    ],
    'Accessories': [
      { id: 'yoga-mat', name: 'Yoga Mat', icon: '/assets/icons/yoga-mat.png' }
    ]
  }
};

export default equipmentConfig;
